// The medication-monitoring dataset, loaded onto the curated-dataset framework
// (issue #995). Copies the ototoxic.ts / pgx.ts shape: import the envelope JSON
// (generated by scripts/gen-medication-monitoring.ts), validate it once with
// loadDataset(), and expose the DRUG entries (drugs whose active use warrants periodic
// lab monitoring, matched by RxCUI ingredient + synonym through the shared
// matchConceptKeysIn machinery) the builder consumes. Identity is the concept `key`
// token (fieldStrategy "key"). The registry lists this for the linter;
// lib/medication-monitoring.ts is the DOMAIN builder. Pure — no DB, no network.

import rawMedMonitoring from "./data/medication-monitoring.json";
import { loadDataset } from "./loader";
import { fieldStrategy } from "./matcher";
import type {
  MedMonitoringEntry,
  MedMonitoringMeta,
} from "@/scripts/gen-medication-monitoring";

export type {
  MedMonitoringEntry,
  MedMonitoringMeta,
  MonitoringLab,
  MonitoringTier,
} from "@/scripts/gen-medication-monitoring";

// The validated dataset (envelope + guarantees). Throws at module load if the committed
// JSON ever violates the contract — a loud, early failure.
export const medMonitoringDataset = loadDataset<
  MedMonitoringEntry,
  MedMonitoringMeta
>(rawMedMonitoring);

// Identity strategy: the concept `key` token, case-folded. For the linter.
export const medMonitoringKeyStrategy = fieldStrategy("key");

// The medication-monitoring entries (concepts) the builder consumes.
export const MED_MONITORING_ENTRIES: MedMonitoringEntry[] =
  medMonitoringDataset.entries;
